mapper.select:
SELECT A.comp_id , A.write_year , A.doc_type , A.doc_no , A.orgn_id , (select Z.orgn_nm from esg.tb_orgn_info Z where Z.orgn_id = A.orgn_id ) AS orgn_nm , A.revised_dt , A.enacted_dt , SUM(CASE WHEN B.USE_YN='N' THEN 0 ELSE 1 END) AS doc_count , A.use_yn AS useYnMain , (CASE WHEN E.signature IS NOT NULL THEN 'Y' WHEN D.signature IS NOT NULL THEN 'I' WHEN C.signature IS NOT NULL THEN 'W' ELSE 'C' END) AS approval_status FROM esg.tb_safety_health_objectives A LEFT JOIN esg.tb_safety_health_objectives_detail B ON B.doc_type = A.doc_type AND B.doc_no = A.doc_no AND B.orgn_id = A.orgn_id LEFT JOIN esg.tb_approval_info C ON C.target_type = A.doc_type AND C.target_id = A.write_year||A.doc_no AND C.param = 'writer' LEFT JOIN esg.tb_approval_info D ON D.target_type = A.doc_type AND D.target_id = A.write_year||A.doc_no AND D.param = 'reviewer' LEFT JOIN esg.tb_approval_info E ON E.target_type = A.doc_type AND E.target_id = A.write_year||A.doc_no AND E.param = 'approver' WHERE A.comp_id = #{compId}
-- 일괄 출력용 and A.write_year = #{writeYear} and A.use_yn = 'Y'
GROUP BY A.comp_id, A.write_year, A.doc_type, A.doc_no, A.orgn_id, E.signature, D.signature, C.signature ORDER BY A.use_yn DESC, A.WRITE_YEAR DESC,A.CREATED_AT DESC;

SELECT A.comp_id
, A.write_year
, A.doc_type
, A.doc_no
, A.orgn_id
, A.use_yn as useYnMain
, (select Z.orgn_nm
from esg.tb_orgn_info Z
where Z.orgn_id = A.orgn_id
) AS orgn_nm
, A.revised_dt
, A.enacted_dt
FROM esg.tb_safety_health_objectives A
WHERE A.comp_id = #{compId}
AND A.write_year = #{writeYear}
AND A.doc_type = #{docType}
AND A.doc_no = #{docNo}
ORDER BY A.use_yn DESC, A.WRITE_YEAR DESC,A.CREATED_AT DESC;

    	SELECT LPAD((COALESCE(MAX(CAST(A.doc_no AS INTEGER)), 0) + 1)::TEXT, 5, '0') AS docNo
		  FROM esg.tb_safety_health_objectives A
		 WHERE A.write_year = #{writeYear};

mapper.insert:
		INSERT INTO esg.tb_safety_health_objectives
 	(
 		  write_year
 		, doc_type
 		, doc_no
 		, orgn_id
 		, comp_id
 		, revised_dt
 		, enacted_dt
 		, use_yn
 		, created_at
 		, created_by
 	)
 	VALUES
 	(
 		  #{writeYear}
 		, #{docType}
 		, #{docNo}
 		, #{orgnId}
 		, #{compId}
 		, #{revisedDt}
 		, #{enactedDt}
 		, 'Y'
 		, now()
 		, #{createdBy}
 	);

   		INSERT INTO esg.tb_safety_health_objectives_detail
    	(
    		  comp_id
    		, write_year
			, doc_type
			, doc_no
			, orgn_id
			, doc_seq
			, safety_health_goal
			, detail_goal_method
			, hr_id
			, required_resource
			, evaluation_method
			, remark
			, action_schedule1
			, action_schedule2
			, action_schedule3
			, action_schedule4
			, action_schedule5
			, action_schedule6
			, action_schedule7
			, action_schedule8
			, action_schedule9
			, action_schedule10
			, action_schedule11
			, action_schedule12
			, action_doc_type
			, action_doc_no
			, action_doc_seq
			, action_doc_detail_seq
			, use_yn
			, created_at
			, created_by
    	)
    	VALUES
    	(
    		  #{compId}
    		, #{writeYear}
			, #{docType}
			, #{docNo}
			, #{orgnId}
			, (SELECT CAST(COALESCE(MAX(doc_seq)::INTEGER, 0) AS INTEGER) + 1
				 FROM esg.tb_safety_health_objectives_detail
				WHERE doc_type = #{docType}
				  AND doc_no = #{docNo}
		      )
			, #{safetyHealthGoal}
			, #{detailGoalMethod}
			, #{hrId}
			, #{requiredResource}
			, #{evaluationMethod}
			, #{remark}
			, #{actionSchedule1}
			, #{actionSchedule2}
			, #{actionSchedule3}
			, #{actionSchedule4}
			, #{actionSchedule5}
			, #{actionSchedule6}
			, #{actionSchedule7}
			, #{actionSchedule8}
			, #{actionSchedule9}
			, #{actionSchedule10}
			, #{actionSchedule11}
			, #{actionSchedule12}
			, #{actionDocType}
			, #{actionDocNo}
			, #{actionDocSeq}
			, #{actionDocDetailSeq}
			, 'Y'
			, now()
			, #{createdBy}
    	);

mapper.update:

UPDATE esg.tb_task_manager_detail
SET cancel_dt = now()
  , task_detail_content = concat(#{taskDetailContent}, '- 취소')
WHERE user_id = #{userId}
AND comp_id = #{compId} 
AND task_year = #{taskYear}
AND task_month = #{taskMonth}
AND task_day = #{taskDay}
AND task_seq = #{taskSeq}
AND detail_seq = #{detailSeq};

UPDATE esg.tb_safety_health_objectives
   SET enacted_dt = #{enactedDt}
   	 , revised_dt = #{revisedDt}
     , orgn_id = #{orgnId}
     , use_yn = #{useYnMain}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE comp_id = #{compId}
   AND write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo};

UPDATE esg.tb_safety_health_objectives_detail
   SET orgn_id = #{orgnId}
   	 , updated_at = now()
   	 , updated_by = #{updatedBy}
 WHERE comp_id = #{compId}
   AND doc_type = #{docType}
   AND doc_no = #{docNo};

 UPDATE esg.tb_hse_key_performance_result
   SET hr_id = #{hrId}
   	 , updated_at = now()
   	 , updated_by = #{updatedBy}
 WHERE doc_type = #{docType}
   AND doc_no = #{docNo}
   AND doc_seq = #{docSeq};

UPDATE esg.tb_safety_health_objectives
   SET use_yn = #{useYnMain}
     , revised_dt = #{revisedDt}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo};

    	UPDATE esg.tb_safety_health_objectives_detail
		   SET safety_health_goal = #{safetyHealthGoal}
